import json
import logging

from channels.generic.websocket import AsyncWebsocketConsumer

from spachat.ollama_client import OllamaModel

logger = logging.getLogger(__name__)


class ChatConsumer(AsyncWebsocketConsumer):
    """WebSocket consumer that streams Ollama responses token by token."""

    async def connect(self):
        await self.accept()
        self._model = None

    async def disconnect(self, close_code):
        pass

    async def receive(self, text_data=None, bytes_data=None):
        if not text_data:
            return

        try:
            data = json.loads(text_data)
        except json.JSONDecodeError:
            await self.send(json.dumps({"type": "error", "message": "invalid JSON"}))
            return

        msg = data.get("message", "").strip()
        if not msg:
            return

        if self._model is None:
            self._model = OllamaModel()

        full_text = ""

        try:
            async for token in self._model.stream(msg):
                full_text += token
                await self.send(json.dumps({
                    "type": "token",
                    "content": token,
                }))
        except Exception as exc:
            logger.exception("Ollama stream failed")
            await self.send(json.dumps({
                "type": "error",
                "content": f"Stream error: {exc}",
            }))
            return

        await self.send(json.dumps({
            "type": "done",
            "content": full_text,
        }))

from django.shortcuts import render


def index(request):
    return render(request, "spachat/index.html")

(function () {
  'use strict';

  const messagesEl = document.getElementById('messages');
  const form = document.getElementById('chat-form');
  const input = document.getElementById('message-input');
  const welcomeMsg = document.getElementById('welcome-msg');

  let ws = null;
  let currentAssistantBubble = null;

  function connectWebSocket() {
    const proto = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    const url = proto + '//' + window.location.host + '/ws/chat/';
    ws = new WebSocket(url);

    ws.onopen = function () {
      console.log('WS connected');
    };

    ws.onmessage = function (event) {
      let data;
      try {
        data = JSON.parse(event.data);
      } catch {
        return;
      }

      if (data.type === 'token') {
        if (!currentAssistantBubble) {
          if (welcomeMsg) welcomeMsg.remove();
          const tpl = document.getElementById('msg-assistant');
          const clone = tpl.content.cloneNode(true);
          messagesEl.appendChild(clone);
          currentAssistantBubble = messagesEl.lastElementChild.querySelector('div:last-child');
        }
        currentAssistantBubble.textContent += data.content;
        messagesEl.scrollTop = messagesEl.scrollHeight;
      } else if (data.type === 'done') {
        currentAssistantBubble = null;
        enableForm();
      } else if (data.type === 'error') {
        if (currentAssistantBubble) {
          currentAssistantBubble.textContent += '\n[Error: ' + (data.content || data.message) + ']';
        } else {
          if (welcomeMsg) welcomeMsg.remove();
          const tpl = document.getElementById('msg-assistant');
          const clone = tpl.content.cloneNode(true);
          clone.querySelector('div:last-child').textContent = 'Error: ' + (data.content || data.message);
          messagesEl.appendChild(clone);
        }
        currentAssistantBubble = null;
        enableForm();
      }
    };

    ws.onclose = function () {
      console.log('WS disconnected, reconnecting in 3s…');
      setTimeout(connectWebSocket, 3000);
    };

    ws.onerror = function () {
      console.error('WS error');
    };
  }

  function sendMessage(text) {
    if (!ws || ws.readyState !== WebSocket.OPEN) {
      alert('WebSocket not connected. Please wait…');
      return;
    }

    if (welcomeMsg) welcomeMsg.remove();

    const tpl = document.getElementById('msg-user');
    const clone = tpl.content.cloneNode(true);
    clone.querySelector('div:last-child').textContent = text;
    messagesEl.appendChild(clone);

    ws.send(JSON.stringify({ message: text }));
    messagesEl.scrollTop = messagesEl.scrollHeight;
  }

  function enableForm() {
    const btn = form.querySelector('button');
    btn.disabled = false;
    btn.textContent = 'Send';
    input.disabled = false;
    input.focus();
  }

  function disableForm() {
    const btn = form.querySelector('button');
    btn.disabled = true;
    btn.textContent = 'Sending…';
    input.disabled = true;
  }

  form.addEventListener('submit', function (e) {
    e.preventDefault();
    const text = input.value.trim();
    if (!text) return;
    input.value = '';
    disableForm();
    sendMessage(text);
  });

  connectWebSocket();
})();

